#include <stdio.h>
#include <stdlib.h>
#include <math.h>

int main() {
    int N, K;
    scanf("%d %d", &N, &K);
    int* X = (int*)malloc(N * sizeof(int));
    int* Y = (int*)malloc(N * sizeof(int));
    for (int i = 0; i < N; i++) {
        scanf("%d %d", &X[i], &Y[i]);
    }
    long long maxArea = -1;
    for (int i = 0; i < N; i++) {
        for (int j = i + 1; j < N; j++) {
            for (int k = j + 1; k < N; k++) {
                long long area = abs((X[i]*(Y[j]-Y[k]) + X[j]*(Y[k]-Y[i]) + X[k]*(Y[i]-Y[j])) / 2);
                if (area * 2 <= K && area > maxArea) {
                    maxArea = area;
                }
            }
        }
    }
    printf("%lld\n", maxArea * 2);
    free(X);
    free(Y);
    return 0;
}

