import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int N = scanner.nextInt();
        long K = scanner.nextLong();
        int[] X = new int[N];
        int[] Y = new int[N];
        for (int i = 0; i < N; i++) {
            X[i] = scanner.nextInt();
            Y[i] = scanner.nextInt();
        }
        long maxArea = -1;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                for (int k = j + 1; k < N; k++) {
                    long area = Math.abs((X[i]*(Y[j]-Y[k]) + X[j]*(Y[k]-Y[i]) + X[k]*(Y[i]-Y[j])) / 2);
                    if (area * 2 <= K && area > maxArea) {
                        maxArea = area;
                    }
                }
            }
        }
        System.out.println(maxArea * 2);
    }
}

